@app.post("/_tokens/issue")
def issue_token():
    data = request.get_json(silent=True) or {}
    subject = data.get("subject", "service")
    client_id = data.get("client_id")
    scope = data.get("scope", "")
    ttl_seconds = int(data.get("ttl_seconds", 3600))

    token_str = secrets.token_urlsafe(32)
    now = datetime.now(timezone.utc)
    expires_at = now + timedelta(seconds=ttl_seconds) if ttl_seconds > 0 else None

    token = AccessToken(
        token=token_str,
        subject=subject,
        client_id=client_id,
        scope=scope,
        issued_at=now,
        expires_at=expires_at,
        revoked=False,
    )
    db.session.add(token)
    db.session.commit()

    return jsonify(
        {
            "access_token": token_str,
            "token_type": "Bearer",
            "expires_in": ttl_seconds if ttl_seconds > 0 else None,
            "scope": scope,
            "subject": subject,
            "client_id": client_id,
        }
    ), 201


@app.post("/_tokens/revoke")
def revoke_token():
    data = request.get_json(silent=True) or {}
    token_str = data.get("token") or _extract_bearer_token(request)
    if not token_str:
        return jsonify({"error": "invalid_request", "error_description": "token is required"}), 400

    token = db.session.query(AccessToken).filter(AccessToken.token == token_str).first()
    if not token:
        return jsonify({"revoked": False, "reason": "not_found"}), 200

    token.revoked = True
    db.session.commit()
    return jsonify({"revoked": True}), 200


